let style = ".lorenz-wrapper{position:fixed;inset:0;z-index:-1;pointer-events:none}.lorenz-canvas{position:fixed;inset:0;z-index:-1;pointer-events:none;display:block}.lorenz-overlay{position:fixed;inset:0;z-index:-1;pointer-events:none;background:radial-gradient(ellipse at center,transparent 50%,rgba(7,30,44,.3) 100%)}.lorenz-slider-toggle{position:fixed;right:0;top:50%;transform:translateY(-50%);z-index:1000;display:flex;align-items:center;pointer-events:auto}.lorenz-slider-toggle .lorenz-slider-tab{width:auto;height:auto;min-height:90px;padding:14px 12px;background:#071e2c;border:1px solid #0a2940;border-right:none;border-radius:8px 0 0 8px;cursor:pointer;opacity:.7;transition:opacity .3s;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:8px}.lorenz-slider-toggle .lorenz-slider-tab::before{content:\"Settings\";font-size:10px;color:#af96dc;letter-spacing:.08em}.lorenz-slider-toggle .lorenz-slider-tab::after{content:\"\\25C0\";font-size:10px;color:#af96dc;opacity:.8}.lorenz-slider-toggle .lorenz-slider-tab:hover{opacity:1}.lorenz-slider-toggle .lorenz-slider-panel{display:none;flex-direction:column;gap:.75rem;padding:1.2rem;background:#071e2c;border:1px solid #0a2940;border-radius:8px 0 0 8px;box-shadow:-2px 0 12px rgba(7,30,44,.6);min-width:220px}.lorenz-slider-toggle .lorenz-slider-panel label{font-size:.85rem;color:#0197d6;display:flex;flex-direction:column;gap:.3rem;font-family:var(--bodyFont)}.lorenz-slider-toggle .lorenz-slider-panel label span{font-size:.75rem;color:#af96dc}.lorenz-slider-toggle .lorenz-slider-panel label input[type=range]{-webkit-appearance:none;appearance:none;width:100%;height:6px;border-radius:3px;background:#0a2940;outline:none}.lorenz-slider-toggle .lorenz-slider-panel label input[type=range]::-webkit-slider-thumb{-webkit-appearance:none;appearance:none;width:16px;height:16px;border-radius:50%;background:#af96dc;cursor:pointer}.lorenz-slider-toggle:hover .lorenz-slider-panel,.lorenz-slider-toggle.active .lorenz-slider-panel{display:flex}.lorenz-slider-toggle.active .lorenz-slider-tab{display:none}@media(max-width:800px){.lorenz-slider-toggle{top:auto;bottom:1rem;right:1rem;transform:none}.lorenz-slider-toggle .lorenz-slider-tab{width:56px;height:56px;border-radius:50%;border:1px solid #0a2940;opacity:.7;flex-direction:column;gap:2px}.lorenz-slider-toggle .lorenz-slider-tab::before{content:\"\\2699\";font-size:22px;color:#af96dc}.lorenz-slider-toggle .lorenz-slider-tab::after{display:none}.lorenz-slider-toggle .lorenz-slider-panel{position:fixed;bottom:0;right:0;left:0;border-radius:12px 12px 0 0;flex-direction:row;flex-wrap:wrap;gap:.5rem;padding:1rem}.lorenz-slider-toggle .lorenz-slider-panel label{flex:1;min-width:80px}.lorenz-slider-toggle:hover .lorenz-slider-panel,.lorenz-slider-toggle.active .lorenz-slider-panel{display:flex}}"

import { jsx, jsxs } from "preact/jsx-runtime"

export default (() => {
  const LorenzBackground = ({ displayClass }) =>
    jsxs("div", {
      class: [displayClass, "lorenz-wrapper"].filter(Boolean).join(" "),
      children: [
        jsx("canvas", { id: "lorenz-canvas", class: "lorenz-canvas" }),
        jsx("div", { class: "lorenz-overlay" }),
        jsxs("div", { class: "lorenz-slider-toggle", id: "lorenz-slider", children: [
          jsx("div", { class: "lorenz-slider-tab", id: "lorenz-slider-tab" }),
          jsxs("div", { class: "lorenz-slider-panel", id: "lorenz-slider-panel", children: [
            jsxs("label", { children: ["\u03C3 (sigma)", jsx("input", { type: "range", id: "lorenz-sigma", min: "6", max: "16", step: "0.1", value: "10" }), jsx("span", { id: "lorenz-sigma-val", children: "10.0" })] }),
            jsxs("label", { children: ["\u03C1 (rho)", jsx("input", { type: "range", id: "lorenz-rho", min: "15", max: "45", step: "0.1", value: "28" }), jsx("span", { id: "lorenz-rho-val", children: "28.0" })] }),
            jsxs("label", { children: ["\u03B2 (beta)", jsx("input", { type: "range", id: "lorenz-beta", min: "1.5", max: "4", step: "0.05", value: "2.667" }), jsx("span", { id: "lorenz-beta-val", children: "2.67" })] }),
            jsxs("label", { children: ["Speed", jsx("input", { type: "range", id: "lorenz-speed", min: "1", max: "20", step: "1", value: "3" }), jsx("span", { id: "lorenz-speed-val", children: "6" })] }),
          ]}),
        ]}),
      ],
    })

  LorenzBackground.css = style
  LorenzBackground.afterDOMLoaded = inlineScript

  return LorenzBackground
})
